import{_ as d,o as e,c as o,ak as a}from"./chunks/framework.C5oxOlRz.js";const p=JSON.parse('{"title":"高级配置","description":"","frontmatter":{"version":"2.1.8"},"headers":[],"relativePath":"guide/feature/advanced.md","filePath":"guide/feature/advanced.md","lastUpdated":1780022608000}'),c={name:"guide/feature/advanced.md"};function r(i,t,l,h,n,s){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="高级配置" tabindex="-1">高级配置 <a class="header-anchor" href="#高级配置" aria-label="Permalink to “高级配置”">​</a></h1><h2 id="_1-webhook-端点模式" tabindex="-1">1. Webhook 端点模式 <a class="header-anchor" href="#_1-webhook-端点模式" aria-label="Permalink to “1. Webhook 端点模式”">​</a></h2><p>添加机器人时，插件支持两种 Webhook 地址配置方式：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td>平台默认模式</td><td>选择平台后只输入 <code>Token</code> 或 <code>Key</code>，插件自动拼接官方 Webhook</td><td>官方 SaaS 地址，优先推荐</td></tr><tr><td>自定义 Webhook</td><td>直接粘贴完整 Webhook URL</td><td>已拿到完整地址、使用私有域名、历史配置迁移</td></tr></tbody></table><p>选择平台后，机器人编辑器会自动切换输入提示、预览最终 Webhook，并记录对应协议类型。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><code>Lark / 飞书</code> 支持自定义域名，只要 Webhook 路径仍为 <code>/open-apis/bot/v2/hook/{token}</code>。</p></div><p>不同平台的默认输入内容如下：</p><table tabindex="0"><thead><tr><th>平台</th><th>默认输入值</th><th>自动拼接结果</th></tr></thead><tbody><tr><td>Lark / 飞书</td><td>机器人 <code>Token</code></td><td><code>https://open.larksuite.com/open-apis/bot/v2/hook/{token}</code> 或 <code>https://open.feishu.cn/open-apis/bot/v2/hook/{token}</code></td></tr><tr><td>钉钉</td><td>机器人 <code>access_token</code></td><td><code>https://oapi.dingtalk.com/robot/send?access_token={token}</code></td></tr><tr><td>企业微信</td><td>群机器人 <code>key</code></td><td><code>https://qyapi.weixin.qq.com/cgi-bin/webhook/send?key={key}</code></td></tr></tbody></table><h2 id="_2-安全策略" tabindex="-1">2. 安全策略 <a class="header-anchor" href="#_2-安全策略" aria-label="Permalink to “2. 安全策略”">​</a></h2><p>每个机器人都可配置以下安全策略：</p><table tabindex="0"><thead><tr><th>策略</th><th>说明</th></tr></thead><tbody><tr><td><strong>关键词（KEY）</strong></td><td>设定后，只有包含关键词的消息内容才会被正常发送，多个值使用逗号分隔。</td></tr><tr><td><strong>签名密钥（SECRET）</strong></td><td>使用 HMAC-SHA256 对消息进行签名验证。需在机器人安全设置中获取密钥。</td></tr><tr><td><strong>禁用 SSL 验证（NO_SSL）</strong></td><td>禁用 Java HTTP 客户端中的 SSL/TLS 证书验证。</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>企业微信群机器人本身没有飞书 / 钉钉那种签名验签流程，但插件仍支持关键词校验与 SSL 控制等通用策略。</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>禁用 SSL 验证会降低连接的安全性，可能导致中间人攻击等安全风险。建议仅在受控测试环境中使用此选项。</p></div><h2 id="_3-重试配置" tabindex="-1">3. 重试配置 <a class="header-anchor" href="#_3-重试配置" aria-label="Permalink to “3. 重试配置”">​</a></h2><p>插件支持对发送失败的 Webhook 消息进行重试，每个机器人可单独配置。默认不开启。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>enabled</code></td><td>boolean</td><td><code>false</code></td><td>是否启用重试</td></tr><tr><td><code>maxAttempts</code></td><td>int</td><td><code>1</code></td><td>最大尝试次数（包含首次发送）</td></tr><tr><td><code>initialDelayMs</code></td><td>long</td><td><code>500</code></td><td>首次重试前的等待时间（毫秒）</td></tr><tr><td><code>maxDelayMs</code></td><td>long</td><td><code>5000</code></td><td>重试等待时间上限（毫秒）</td></tr><tr><td><code>backoffMultiplier</code></td><td>double</td><td><code>2.0</code></td><td>退避倍数（必须 &gt;= 1.0）</td></tr><tr><td><code>jitterRatio</code></td><td>double</td><td><code>0.2</code></td><td>等待时间抖动比例（0.0 ~ 1.0）</td></tr></tbody></table><p>重试采用指数退避策略，每次重试的等待时间 = 上次等待 × <code>backoffMultiplier</code>，并叠加随机抖动以避免请求风暴。</p><p>高级选项（<code>initialDelayMs</code>、<code>maxDelayMs</code>、<code>backoffMultiplier</code>、<code>jitterRatio</code>）默认折叠，点击「高级」可展开配置。</p><h2 id="_4-消息语言" tabindex="-1">4. 消息语言 <a class="header-anchor" href="#_4-消息语言" aria-label="Permalink to “4. 消息语言”">​</a></h2><p>每个机器人可独立设置消息语言，影响内置卡片标题和默认模板的显示语言。</p><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>中文</td><td>使用简体中文显示内置消息</td></tr><tr><td>EN</td><td>使用英文显示内置消息</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>仅影响内置卡片标题与默认模板，自定义消息内容不做翻译。</p></div><h2 id="_4-1-平台消息能力差异" tabindex="-1">4.1 平台消息能力差异 <a class="header-anchor" href="#_4-1-平台消息能力差异" aria-label="Permalink to “4.1 平台消息能力差异”">​</a></h2><p>虽然插件对外统一暴露了消息模式，但不同平台底层支持能力并不完全相同：</p><table tabindex="0"><thead><tr><th>平台</th><th>重点支持</th></tr></thead><tbody><tr><td>Lark / 飞书</td><td><code>TEXT</code>、<code>IMAGE</code>、<code>SHARE_CHAT</code>、<code>POST</code>、<code>MARKDOWN</code>、<code>CARD</code>，以及 Freestyle 自定义 JSON 卡片</td></tr><tr><td>钉钉</td><td><code>TEXT</code>、<code>LINK</code>、<code>MARKDOWN</code>、<code>CARD</code></td></tr><tr><td>企业微信</td><td><code>TEXT</code>、<code>MARKDOWN</code>、<code>CARD</code></td></tr></tbody></table><p>企业微信的补充说明：</p><ul><li><code>Freestyle</code> 下更推荐使用默认卡片模式；如需精确控制消息结构，优先使用 <code>Pipeline</code> 的 <code>wechatWork</code> 步骤。</li><li><code>Pipeline</code> 中传入 <code>LINK</code> 或 <code>POST</code> 时，插件会按 <code>MARKDOWN</code> 发送。</li><li><code>IMAGE</code> 不是企业微信独立支持的消息类型；需要图片时，优先使用卡片 <code>picUrl</code> 或 <code>topImg.imgKey</code> 中的外部图片 URL。</li><li>企业微信卡片使用 <code>template_card.news_notice</code> 模板，不是飞书那种自由结构卡片。</li><li>企业微信卡片图片需要可直接访问的 <code>http/https</code> 地址；如果未提供可用图片地址，插件会回退到默认 Jenkins 图片。</li><li>企业微信卡片最多展示 3 个跳转按钮。</li></ul><h2 id="_5-代理配置" tabindex="-1">5. 代理配置 <a class="header-anchor" href="#_5-代理配置" aria-label="Permalink to “5. 代理配置”">​</a></h2><p>当 Jenkins 无法直连机器人 Webhook 地址时，可在全局配置中设置网络代理。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>enabled</code></td><td>是否启用代理</td></tr><tr><td><code>type</code></td><td>代理类型：<code>HTTP</code> 或 <code>SOCKS</code></td></tr><tr><td><code>host</code></td><td>代理服务主机，如 <code>127.0.0.1</code></td></tr><tr><td><code>port</code></td><td>代理服务端口，如 <code>1080</code></td></tr></tbody></table><p>代理配置位于 <code>Manage Jenkins</code> -&gt; <code>Lark Notice</code> 或 <code>System Configuration</code> 页面中的 <code>代理</code> 区域。</p><h2 id="_6-详细日志" tabindex="-1">6. 详细日志 <a class="header-anchor" href="#_6-详细日志" aria-label="Permalink to “6. 详细日志”">​</a></h2><p>在全局配置的「日志」区域，可开启 <code>启用详细日志</code> 选项。</p><p>开启后，插件会在 Jenkins 系统日志中输出更详细的请求和响应信息，适用于排查消息发送失败等问题。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>排查完毕后建议关闭详细日志，避免日志量过大。</p></div><h2 id="_7-通知触发时机" tabindex="-1">7. 通知触发时机 <a class="header-anchor" href="#_7-通知触发时机" aria-label="Permalink to “7. 通知触发时机”">​</a></h2><p>在全局配置中可设置默认的通知触发时机，同时每个任务也可单独覆盖。</p><table tabindex="0"><thead><tr><th>时机</th><th>说明</th></tr></thead><tbody><tr><td>构建开始（START）</td><td>构建启动时触发</td></tr><tr><td>构建成功（SUCCESS）</td><td>构建成功完成时触发</td></tr><tr><td>构建失败（FAILURE）</td><td>构建失败时触发</td></tr><tr><td>构建不稳定（UNSTABLE）</td><td>构建结果为不稳定时触发</td></tr><tr><td>构建中止（ABORTED）</td><td>构建被手动或自动中止时触发</td></tr><tr><td>未构建（NOT_BUILT）</td><td>构建未执行时触发</td></tr></tbody></table><h2 id="_8-配置导入导出" tabindex="-1">8. 配置导入导出 <a class="header-anchor" href="#_8-配置导入导出" aria-label="Permalink to “8. 配置导入导出”">​</a></h2><p>插件支持将全局配置导出为 JSON 文件，也可从 JSON 文件导入配置。此功能可用于：</p><ul><li>在多个 Jenkins 实例之间同步机器人配置</li><li>备份和恢复配置</li><li>通过脚本批量管理配置</li></ul><p>配置快照包含所有机器人、安全策略、重试配置、代理设置等信息，导入时会校验数据格式版本。</p>',42)])])}const k=d(c,[["render",r]]);export{p as __pageData,k as default};
